mask_eng = books['details'].str.contains('English', case=False, na=False) | books['categories'].str.contains('English', case=False, na=False) | books['title'].str.contains('English', case=False, na=False)
books_filt = books[mask_lit & mask_eng].copy()

# fuzzy join via common numeric id part
